export interface CountyDatum {
  slug: string;
  countyName: string;
  countySeat: string;
  population?: number;
  courthouseAddress?: string;
  heroLead: string;
}

const lead = (countyName: string, seat: string, extra?: string): string => {
  const base = `Licensed and bonded process server covering ${countyName}, Oklahoma, from the ${seat} county seat to every town and rural route in the county. We deliver summons, subpoenas, evictions, and civil documents with GPS-verified attempts and notarized affidavits ready for filing.`;
  const tail = ` Standard, rush, and same-day service tiers are available; see current rates on our pricing page or call (539) 367-6832 to schedule.`;
  return extra ? `${base} ${extra}${tail}` : `${base}${tail}`;
};

